#include<iostream>#include<vector>#include<algorithm>#define ll long longusing namespace std;int main(){    int t;    cin>>t;    while(t--){        ll n,x;        cin>>n>>x;        vector<ll> a(n);        for(int i=0;i<n;i++){            cin>>a[i];        }        int i=1;        int j= 1e12;        ll ans=0;        while(i<j){            ll sum=0;            int mid= i + (j-i)/2;            for(int k=0;k<n;k++){                if(mid>a[k]){                    sum+= (mid-a[k]);                }            }            if(sum<=x){                ans=mid;                i= mid+1;            }            else{                j= mid;            }         }        cout<<ans<<"\n";    }}